diff --git a/app/renderer/src/components/query-field/query-field.spec.js b/app/renderer/src/components/query-field/query-field.spec.js
index aa394cd..dd2ee1b 100644
--- a/app/renderer/src/components/query-field/query-field.spec.js
+++ b/app/renderer/src/components/query-field/query-field.spec.js
@@ -2,23 +2,33 @@ import React from 'react';
 import renderer from 'react-test-renderer';
 import QueryField from './query-field';

+jest.mock('electron', () => ({
+  ipcRenderer: {
+    on: jest.fn(),
+  },
+}));
+
+const createTestProps = custom => ({
+  onReset: jest.fn(),
+  onChange: jest.fn(),
+  ...custom,
+});
+
 describe('<QueryField /> component', () => {
-  let theme = {};
+  let props;

   beforeEach(() => {
-    theme = {};
+    props = createTestProps();
   });

   it('should render a query field component with no value', () => {
-    const component = renderer.create(<QueryField theme={theme} />);
+    const component = renderer.create(<QueryField {...props} />);
     const tree = component.toJSON();
     expect(tree).toMatchSnapshot();
   });

   it('should render a query field component with some value', () => {
-    const component = renderer.create(
-      <QueryField theme={theme} value={'TEST'} />
-    );
+    const component = renderer.create(<QueryField {...props} />);
     const tree = component.toJSON();
     expect(tree).toMatchSnapshot();
   });

